%%%%%%%%%% Function fLblFocusV01.m %%%%%%%%%%% Function Label for focus analysis, ver.1% Kei Nakamura% Created on Thursday, October 27th 2011.% Modified on %%% main bodyfunction [ttl,lbl,outT] = fLblFocusV01(a)  %function headerif isempty(a)    a = 'a';end%% for plot titlettl{1} = ' ';%% for labellbl{1} = 'x [\mum]';lbl{2} = 'y [\mum]';lbl{3} = 'z [mm]';lbl{4} = 'FWHM [\mum]';lbl{5} = 'std [\mum]';lbl{6} = 'max count';lbl{7} ='[a.u.]';%% for output logoutT{1} = [a ' shot'];                   % title for Text outputoutT{2} = [a ' img exist']; outT{3} = [a ' z [mm]'];      outT{4} = [a ' total counts'];outT{5} = [a ' max count']; outT{6} = [a ' peakX'];outT{7} = [a ' peakY'];outT{8} = [a ' meanX'];outT{9} = [a ' meanY']; outT{10} = [a ' fwhmX']; outT{11} = [a ' fwhmY']; outT{12} = [a ' stdX']; outT{13} = [a ' stdY'];outT{14} = [a ' 45peakX'];outT{15} = [a ' 45peakY'];outT{16} = [a ' 45meanX'];outT{17} = [a ' 45meanY']; outT{18} = [a ' 45fwhmX']; outT{19} = [a ' 45fwhmY']; outT{20} = [a ' 45stdX']; outT{21} = [a ' 45stdY'];
